import math

def is_prime(num: int) -> bool:
    if num < 2:
        return False
    for i in range(2, int(math.sqrt(num)) + 1):
        if num % i == 0:
            return False
    return True

def reverse_number(n: int) -> int:
    reversed_num = 0
    while n > 0:
        reversed_num = reversed_num * 10 + n % 10
        n //= 10
    return reversed_num

def solve(n: int) -> int:
    r = reverse_number(n)
    start = min(n, r)
    end = max(n, r)
    total = 0
    for num in range(start, end + 1):
        if is_prime(num):
            total += num
    return total
